/*
 * The following duplicates Google Analytics hits to each UAID present in the data layer
 * Read More: https://www.simoahava.com/gtm-tips/send-google-analytics-tag-multiple-properties/
 */

function() {  
  var globalSendTaskName = 'ckf_originalSendTask';
  return function(customModel) {
    window[globalSendTaskName] = window[globalSendTaskName] || customModel.get('sendHitTask');
    customModel.set('sendHitTask', function(sendModel) {

      // Send hit to global property
      var hitPayload = sendModel.get('hitPayload');
      if({{Debug Mode}}) console.log("Sending hit to global property");
      window[globalSendTaskName](sendModel);

      // Copy hit to other properties
      var old_id = new RegExp(sendModel.get('trackingId'), 'gi');
      var ID_array = {{Data Layer - Analytics ID}};
      if(ID_array){
        for(var i=0;i<ID_array.length;i++){
          new_id = ID_array[i];
          if({{Debug Mode}}) console.log("Replacing: " + old_id + " and sending hit to property: " + new_id);
          sendModel.set('hitPayload', hitPayload.replace(old_id, new_id), true);
          window[globalSendTaskName](sendModel);
        }
      }
    });
  };
}

