function(){
  // Get internal domains array if it exists
  var internalDomainsArray = {{Internal Domains Array}} || [];

  // Add the current domain 
  internalDomainsArray.push({{Page Hostname}});

  // RegEx-ify the items
  var internalDomains = internalDomainsArray.join('|').replace('.','\.');

  // Build the rest of the RegEx
  // https?:\/\/ => if the link starts with http or https
  // ([\?\/].*)?$ => and the hostname (everything before the first / or ?
  // ((?!" + internalDomains + ").)* => does not match the list of internal domains
  var regex = new RegExp("^https?:\/\/((?!" + internalDomains + ").)*([\?\/].*)?$", 'i');

  // Return outbound boolean
  return regex.test({{Link | link_url}});
}

